message.content:
変更ファイル名  
20_api_netshop.gs

差分要約  
新規関数 api_updateItem(id, payload) を追加し、指定された ID に基づいて既存データを更新できるようにします。

```diff
--- 20_api_netshop.gs
+++ 20_api_netshop.gs
@@ -0,0 +1,25 @@
+function api_updateItem(id, payload) {
+  // Spreadsheet を取得
+  var ss = SpreadsheetApp.getActiveSpreadsheet();
+  // CONFIG.SHEET_NAME のシートを取得
+  var sheet = ss.getSheetByName(CONFIG.SHEET_NAME);
+  
+  // 全データを取得
+  var data = sheet.getDataRange().getValues();
+  
+  // ID列から対象行を検索
+  var idIndex = CONFIG.COLS.ID; // ID列のインデックスを取得
+  var rowIndex = -1;
+  
+  for (var i = 1; i < data.length; i++) { // ヘッダーをスキップ
+    if (data[i][idIndex] == id) {
+      rowIndex = i;
+      break;
+    }
+  }
+  
+  // 該当行に対して payload の値で上書き更新
+  if (rowIndex !== -1) {
+    for (var key in payload) {
+      var colIndex = CONFIG.COLS[key];
+      if (colIndex !== undefined) {
+        data[rowIndex][colIndex] = payload[key];
+      }
+    }
+    sheet.getRange(rowIndex + 1, 1, 1, data[rowIndex].length).setValues([data[rowIndex]]);
+    return { status: '成功', updatedData: data[rowIndex] };
+  } else {
+    return { status: '失敗', message: 'IDが見つかりません' };
+  }
+}
``` 

CODEX_INSTRUCTION: 新規関数 api_updateItem を追加し、指定IDに基づいてデータを更新する。CONFIG.COLS を使用し、列番号をハードコードしないでください。シート操作はこの関数内のみにして、既存の api_createItem / api_listItems に影響を与えないようにしてください。
